sql:
SELECT avg_daily_sold AS average_daily_sales
FROM region_item_data
WHERE item_id = 4360 AND region_id = 1;

SELECT AVG(market_value) AS average_market_value
FROM markets
WHERE is_auctionable = 1;

SELECT market_value
FROM markets
WHERE item_id = 4360;

SELECT item_id
FROM item_market_data
WHERE market_value = (SELECT MAX(market_value) FROM item_market_data);

SELECT MAX(market_value) AS max_market_value
FROM markets
WHERE is_auctionable = 1;

SELECT COUNT(*) 
FROM vendor_item_data 
WHERE is_popular = 1;

external_knowledge:
- High-end items may refer to items with high average sale prices; 
- Substantial discounts refer to a discount rate greater than 5%, meaning the price reduction is significant; 
- High demand refers to a sale rate of more than 2%, indicating the item is frequently sold.

